/**
 * Typsnitten som base64-strängar, inbäddade direkt i källkoden.
 *
 * Genererad EN GÅNG från src/fonts/*.ttf (se den mappen för OFL-licenserna).
 * Filerna ändras inte, så det finns ingen anledning att läsa dem vid varje
 * bygge -- och just det ("läs en fil vid build/runtime") är precis det som
 * gick sönder två gånger: readFileSync+import.meta.url fungerade i dev men
 * inte i Cloudflares byggmiljö (fel relativ sökväg efter att Astro flyttat
 * den kompilerade modulen), och Vites ?arraybuffer-importsuffix visade sig
 * INTE ge en ArrayBuffer i den här Vite-versionen -- det gav en URL-sträng,
 * vilket satori sen försökte tolka som fontdata.
 *
 * Base64-konstanter har ingen sådan miljöberoende: de är bara text i en
 * committad fil, identiska i dev, i CI, och i vilken bundlare som helst.
 *
 * Om typsnitten någonsin behöver bytas: kör om skriptet som genererade denna
 * fil (se kommentar i og.ts) mot de nya .ttf-filerna i src/fonts/.
 */
export const LORA_BOLD_BASE64 =
  "";

